"""
MKT Christ Commentary — 2 Chronicles chapters 25–28
Run: python3 scripts/zc-christ-2chronicles-25-28.py

Ch25: Amaziah's partial heart — incomplete righteousness vs. Christ's perfect obedience
      Individual accountability (Deut 24:16) — the Torah principle Christ exhausts on behalf of all
      Futility of defeated gods — Christ's disarming of principalities and powers (Col 2:15)
Ch26: Uzziah's pride-after-strength — the pattern Christ refused (Phil 2:6-7)
      Priestly boundary — Christ as the only qualified priest-king (Heb 7:24)
      Uzziah the leper isolated — Christ who touched lepers without defilement
Ch27: Jotham's ordered ways — the covenant-fidelity pattern that Christ fulfills perfectly
Ch28: Ahaz — the representative king whose sin ruins the people; Christ as the representative king whose righteousness rescues
      Gehenna / Valley of Hinnom — child-sacrifice → Christ's warning about eternal judgment
      The compassion-action chain (28:15) — Good Samaritan type; Luke 10:33
      Ahaz shuts the temple — contrast: Christ opens the way into the Most Holy Place (Heb 10:19-20)

mkt-christ requires an entry for every verse (87 total).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "25": {
    "1": "<p>Amaziah became king at 25 and reigned 29 years in Jerusalem. His mother's name was Jehoaddan of Jerusalem — a detail the Chronicler includes for covenant genealogical purposes. Every king's reign is measured against the Davidic standard. Christ is the fulfillment of that standard: not measured against it but embodying it — the one king whose reign is not bounded by years and whose mother (Mary of Nazareth) is named in the genealogy of the true Davidic heir (Matt 1:16).</p>",
    "2": "<p>Amaziah did what was right in the eyes of YHWH, yet not with a whole heart (<em>lōʾ bᵉlēḇāḇ šālēm</em>). The qualified praise is the Chronicler's most common verdict on the kings: right-but-incomplete. The divided heart is the condition of the covenant people without the new covenant's surgery (Jer 31:33; Ezek 36:26). Christ is the antithesis of the divided heart: 'I always do the things that are pleasing to him' (John 8:29); 'my food is to do the will of him who sent me' (John 4:34) — undivided, total, perfect obedience.</p>",
    "3": "<p>Once established, Amaziah executed his father's assassins. He waited until 'the kingdom was established for him' — political prudence restraining revenge. The justice he delayed is the Chronicler's occasion to cite the Torah (v. 4). Christ does not delay justice but fulfills it: 'do you think that I cannot appeal to my Father, and he will at once send me more than twelve legions of angels?' (Matt 26:53) — the voluntary restraint of the one who had all power.</p>",
    "4": "<p>Amaziah did not execute the sons of the assassins, citing Deut 24:16: 'each person shall die for his own sin.' The individual moral accountability principle drawn from Torah. Christ exhausts this principle on behalf of all: he died for others' sins, not his own (1 Pet 3:18: 'Christ also suffered once for sins, the righteous for the unrighteous') — the one person who could die for others because he had no sin of his own for which to die.</p>",
    "5": "<p>The military census: 300,000 troops from Judah and Benjamin, able-bodied men. The enumeration of fighting capacity before battle. Christ does not enumerate his forces — his kingdom does not advance by counting soldiers (Zech 4:6: 'not by might, nor by power, but by my Spirit'). The one who could command twelve legions of angels (Matt 26:53) chose the cross.</p>",
    "6": "<p>Amaziah hired 100,000 Israelite mercenaries for 100 talents of silver. The purchase of military help — the covenant equivalent of trusting in an arm of flesh. Christ does not hire help; he sends his Spirit as the 'Helper' (John 14:26, <em>paráklētos</em>) — not a purchased auxiliary but the divine co-worker who comes as gift.</p>",
    "7": "<p>The man of God warns against taking the north Israelite troops: 'YHWH is not with Israel — not with all the Ephraimites.' The warning is about contaminated alliances — yoked to those under divine judgment. Paul draws this principle in 2 Cor 6:14-15: 'do not be unequally yoked with unbelievers; for what partnership has righteousness with lawlessness?' Christ came to reconcile, not to be contaminated by what he reconciles — 'he was numbered with the transgressors' (Isa 53:12) but was not himself a transgressor.</p>",
    "8": "<p>'God has power to help or to cast down' (25:8) — the prophet's statement that divine sovereignty underlies all military outcomes. Paul makes the same claim from prison (Phil 4:13: 'I can do all things through him who strengthens me') and from weakness (2 Cor 12:9: 'my power is made perfect in weakness'). The acknowledgment of divine sovereignty is the ground of courage without human alliance.</p>",
    "9": "<p>Amaziah's concern about the 100 talents already paid for the mercenaries — the money is lost if they're sent home. The prophet's answer: 'YHWH is able to give you much more than this.' The principle that divine provision exceeds financial loss governs Christ's invitation to the rich young ruler (Matt 19:21: 'sell what you possess and give to the poor... and come, follow me') — the one who asks for the 100 talents can give 'much more.'</p>",
    "10": "<p>Amaziah dismissed the Israelite troops angrily. The separation from contaminated alliances produces conflict — the mercenaries are furious. Following Christ's call also produces conflict: 'I did not come to bring peace, but a sword' (Matt 10:34). The sword of separation is the cost of undivided allegiance.</p>",
    "11": "<p>Amaziah led his troops to the Valley of Salt and struck down 10,000 Edomites. Victory in the designated battle. The covenant reward for the obedient act (sending the mercenaries away) is military success in the appointed theater. Christ's obedience unto death (Phil 2:8) is followed by the appointed victory: resurrection and exaltation (Phil 2:9-11).</p>",
    "12": "<p>Judah captured 10,000 more Edomites and threw them from the top of the cliff, so that they were all dashed to pieces. A severe act of battle-judgment. The OT battle victory has a violent execution-of-judgment aspect that the NT transforms: Christ 'leads captives in his train' (Eph 4:8, citing Ps 68:18) — the victory still captures enemies but the outcome is now release rather than destruction. 'He has delivered us from the domain of darkness and transferred us to the kingdom of his beloved Son' (Col 1:13).</p>",
    "13": "<p>The dismissed Israelite mercenaries raided towns of Judah from Samaria to Beth-horon, killing 3,000. The cost of the refused alliance — former allies become attackers. The enemies Christ defeats are not former allies but the powers of sin and death; his victory removes the penalty and power of those forces rather than creating new enemies among the freed.</p>",
    "14": "<p>Amaziah brought back the gods of Edom and set them up as his own gods, bowing to them and burning incense to them. The absurdity is complete: he defeated Edom, so he adopts Edom's gods — the gods who demonstrably failed their worshippers. Christ's victory does not include adopting the enemy's religious framework; rather 'he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). Victory means the conquered powers are exposed, not installed.</p>",
    "15": "<p>YHWH's anger burns against Amaziah: 'Why have you sought the gods of a people who did not deliver their people from your hand?' The futility-of-idolatry argument in its sharpest form. Christ makes the same claim about all rival lords: 'all who came before me are thieves and robbers, but the sheep did not listen to them' (John 10:8). The gods who fail their people cannot save others.</p>",
    "16": "<p>The prophet is silenced by Amaziah: 'Have we appointed you as a royal counselor? Stop!' The prophet withdraws with the announcement: 'I know that God has determined to destroy you.' The refusal to hear the divine word seals judgment. Christ speaks to the same pattern: 'Whoever is of God hears the words of God. The reason why you do not hear them is that you are not of God' (John 8:47). Rejection of the divine word is the diagnostic of a heart already hardened.</p>",
    "17": "<p>Amaziah challenges Joash of Israel: 'Come, let us look at one another in the face.' The provocative challenge after his Edomite victory leads to a disaster. The pride of military success breeding contempt for neighbors — the same pride Uzziah will display in ch 26. Christ warns against this pride-spiral: 'everyone who exalts himself will be humbled' (Luke 14:11).</p>",
    "18": "<p>Joash's thistle-and-cedar parable: a thornbush on Lebanon sent to a cedar demanding a marriage alliance; then a wild beast trampled the thornbush. The parable mocks Amaziah's pretension — he is the thistle challenging the cedar. Christ uses parables to expose the same self-inflated pretension (Luke 14:7-11: taking the seats of honor only to be displaced). The kingdom belongs to those who are humble, not those who overreach.</p>",
    "19": "<p>'You have indeed struck down Edom, and your heart has lifted you up in pride.' The diagnosis: military success producing pride. The same sequence appears in Uzziah (26:16) and Hezekiah (32:25). Christ is the exception — the one in whom success produces no pride, in whom 'I can do nothing on my own' (John 5:30) remains the operative principle even at the apex of his ministry.</p>",
    "20": "<p>Amaziah did not listen — 'for it was of God, in order that he might give them into the hand of Joash, because they had sought the gods of Edom.' The divine providential hardening through the fruit of the king's own idolatry. Christ's warning: 'to the one who has, more will be given, and from the one who has not, even what he has will be taken away' (Matt 13:12) — covenant faithfulness compounds; covenant unfaithfulness also compounds, until the point of handing over.</p>",
    "21": "<p>Joash of Israel defeated Judah at Beth-shemesh. The very city whose name means 'house of the sun' becomes the site of Judah's humiliation. The reversal of fortune is complete: the proud challenger is defeated. Christ accepts the apparent defeat of the cross — the humiliation that precedes the glorification — but his defeat was not the fruit of pride; it was the instrument of the victory over death.</p>",
    "22": "<p>Judah was defeated before Israel, and every man fled to his tent. The complete rout of the army — covenant curse in military form. The disciples also fled at Christ's arrest: 'they all left him and fled' (Mark 14:50). In both cases the moment of the leader's defeat scatters the followers. But Christ's followers are regathered by resurrection (Matt 28:10, 16-17), not by the king's military recovery.</p>",
    "23": "<p>Joash broke down 400 cubits of Jerusalem's wall — the Ephraim Gate to the Corner Gate. The physical breach of Jerusalem's defenses. The true breach of the enemy's power over Jerusalem comes through Christ: 'on this rock I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18) — not walls broken but gates that cannot hold against his advance.</p>",
    "24": "<p>Joash seized gold, silver, and vessels from the temple, and hostages, and returned to Samaria. The temple stripped by a northern king — a foretaste of the Babylonian stripping to come. Christ's passion includes the stripping of his garments (Mark 15:24) — the reverse despoliation; in his stripping he becomes the true ransom (Mark 10:45).</p>",
    "25": "<p>Amaziah lived fifteen years after the death of Joash. The survival after defeat — an extended reign in diminished status. The Chronicler implies that the extra fifteen years are under the shadow of the defeat and apostasy. Christ's resurrection is not diminished survival but total vindication — the opposite of Amaziah's truncated legacy.</p>",
    "26": "<p>From the time that Amaziah turned away from YHWH, a conspiracy formed against him in Jerusalem. The apostasy and the political unraveling are linked — one follows the other in the Chronicler's theology. Christ faces conspiracy from the Passion's entry point onward (John 11:53: 'from that day on they made plans to put him to death') — but the conspiracy is the occasion for the fulfillment of God's purpose, not its frustration.</p>",
    "27": "<p>Amaziah fled to Lachish but they sent after him and killed him there. Death in flight — the humiliating end of a king who began with partial righteousness and ended in apostasy. Christ also was pursued to his death, but not in flight — 'no one takes it from me, but I lay it down of my own accord' (John 10:18). The contrast between the king fleeing his death and the King who walks toward his is the contrast between involuntary tragedy and voluntary sacrifice.</p>",
    "28": "<p>They brought Amaziah on horses and buried him in the City of David. Burial in the royal tomb despite the apostasy — a minimum of covenantal honor preserved. The burial ends the account. Christ was buried 'in a rich man's tomb' (Matt 27:60), fulfilling Isa 53:9, but the tomb was not the end — 'why do you seek the living among the dead?' (Luke 24:5). The burial that concludes every previous king's account is only the midpoint of Christ's story.</p>"
  },
  "26": {
    "1": "<p>All the people of Judah took Uzziah (Azariah) and made him king at age sixteen. The popular coronation of the boy king after his father's assassination. Christ is not acclaimed by popular coronation initially — he is rejected by the crowds ('crucify him') before his enthronement at the resurrection. The true anointing is not popular but divine: 'this is my beloved Son' (Matt 3:17).</p>",
    "2": "<p>Uzziah built Elath and restored it to Judah. The recovery of strategic territory on the Red Sea trade route. Christ's kingdom building does not recover lost territories but creates a new people: 'I have other sheep that are not of this fold' (John 10:16) — the expansion is not geographic reclamation but salvific inclusion.</p>",
    "3": "<p>Uzziah reigned fifty-two years in Jerusalem. The longest reign of any Judahite king — a reign that begins in covenant faithfulness (vv. 4-5) and ends in covenant transgression (vv. 16-21). Length of reign is not the measure of covenant success. Christ's reign has no measured length — 'of the increase of his government and of peace there will be no end' (Isa 9:7).</p>",
    "4": "<p>Uzziah did what was right in the eyes of YHWH, according to all that his father Amaziah had done. The qualified continuity with his father's partial righteousness. Christ does not inherit the partial righteousness of any predecessor; he is the source of righteousness, not its recipient: 'the righteousness of God through faith in Jesus Christ for all who believe' (Rom 3:22).</p>",
    "5": "<p>'He set himself to seek God in the days of Zechariah, who instructed him in the fear of God; and as long as he sought YHWH, God made him prosper.' The <em>dārash</em> principle: seeking God generates divine blessing. Christ himself is the fulfillment of this pattern — the one in whom seeking the Father and being prospered by the Father are not sequential but simultaneous: 'the Father who dwells in me does his works' (John 14:10). In him seeking and finding are perfectly united.</p>",
    "6": "<p>Uzziah's military campaigns against the Philistines — breaking down walls, building cities in Philistine territory. The expansion of the covenant's geographic reach through military power. Christ breaks down walls of a different kind: 'he is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:14) — not city walls but the wall between Jew and Gentile.</p>",
    "7": "<p>God helped him against the Philistines, the Arabians, and the Meunites. The divine help is named explicitly — Uzziah's success is attributed to YHWH rather than to his own military genius. Christ is the one who acts entirely from divine empowerment: 'I do nothing on my own authority, but speak just as the Father taught me' (John 8:28). All genuine victory is always divine victory.</p>",
    "8": "<p>The Ammonites paid tribute; his fame spread as far as Egypt, for he became very strong. The widening reputation of Uzziah's kingdom — Gentile nations acknowledging Judah's power. Christ's fame also spread among the nations, but the proclamation was of his name for salvation: 'his name will be proclaimed in all nations, beginning from Jerusalem' (Luke 24:47). The fame that spreads from the true Davidic king brings not tribute but transformation.</p>",
    "9": "<p>Uzziah built towers in Jerusalem at key gates and at the Corner. The defensive building program — investing military success in structural security. Christ builds a different kind of security: 'I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18). The security he builds is not masonry but the covenant community's indestructibility.</p>",
    "10": "<p>Uzziah loved the soil — he built towers in the wilderness, dug cisterns, had livestock in the lowlands and plains. The farmer-king, whose agricultural development is a blessing to the land. Christ provides abundance from soil of a different kind: the sower who sows the word, yielding 'a hundred, sixty, and thirtyfold' (Matt 13:8). The agricultural metaphor is his own — he is the true farmer who tends the eternal harvest.</p>",
    "11": "<p>Uzziah had an army organized by divisions under skilled commanders — a professional military establishment. The organized military reflects the flourishing of Uzziah's reign. Christ's 'army' is organized by gifts of the Spirit (1 Cor 12), deployed not in military campaigns but in the ministry of reconciliation (2 Cor 5:18-20).</p>",
    "12": "<p>The total number of family heads of the mighty men of valor was 2,600. The inventory of fighting capacity. The true inventory that matters in Christ's kingdom is not fighting capacity but spiritual gifting: 'to each is given the manifestation of the Spirit for the common good' (1 Cor 12:7). The census of charismata rather than of chariots.</p>",
    "13": "<p>Under their command was an army of 307,500 who could make war with mighty power to help the king. The vast military at Uzziah's disposal. Christ has at his command more than twelve legions of angels (Matt 26:53) but deploys none of them to prevent the cross — 'not as I will, but as you will' (Matt 26:39). Power restrained in service of the redemptive plan.</p>",
    "14": "<p>Uzziah provided shields, spears, helmets, coats of mail, bows, and sling stones — comprehensive military equipment. Paul takes up the military equipment metaphor for the spiritual life (Eph 6:10-18), but the armor is not for offense against other humans: 'we do not wrestle against flesh and blood, but against... the spiritual forces of evil in the heavenly places' (Eph 6:12). Christ is both the armor-giver and the one who won the battle against those forces.</p>",
    "15": "<p>Skillful men devised engines for the towers and corners to shoot arrows and hurl large stones — the earliest biblical reference to mechanical artillery. Uzziah's technological investment in defense. Christ does not invest in defensive technology but 'for the joy that was set before him endured the cross, despising the shame' (Heb 12:2). The defense is not technological but covenantal — the Father's promise to the Son.</p>",
    "16": "<p>'But when he became strong, his heart was lifted up, so that he acted corruptly: he was unfaithful to the LORD his God.' The pride-after-strength trajectory — the Chronicler's pattern for royal collapse. Christ is the exception to this pattern: the one in whom strength and humility remain permanently united — 'I am gentle and lowly in heart' (Matt 11:29) said at the height of his ministry, not before it.</p>",
    "17": "<p>Azariah the priest, with eighty priests of YHWH, came in and confronted Uzziah. The priestly courage to confront the king — risking the king's anger to uphold the covenantal boundary. Christ exercises both the royal and priestly offices without tension — 'a priest forever after the order of Melchizedek' (Heb 7:17) who also rules on David's throne. In him the priestly and royal offices are united, not in conflict.</p>",
    "18": "<p>'It is not for you, Uzziah, to burn incense to the LORD, but for the priests, the sons of Aaron, who are consecrated to burn incense. Go out of the sanctuary; for you have done wrong.' The priestly boundary enforced. Christ crosses this boundary legitimately: as the unique priest-king of Melchizedek's order (Gen 14:18; Heb 7:1-17), he exercises both royal and priestly authority without violating either — he is 'holy, innocent, unstained, separated from sinners' (Heb 7:26) and so qualified to be the priest that Uzziah could not be.</p>",
    "19": "<p>Uzziah, while angry, had leprosy break out on his forehead while holding the censer. The divine verdict through physical affliction — the holy fire that Uzziah usurped becomes the leprosy-judgment. Christ did not avoid lepers but touched them (Matt 8:3: 'I will; be clean'), reversing the flow: instead of holiness being contaminated by leprosy, his holiness cleanses the leprous.</p>",
    "20": "<p>The priests looked and saw the leprosy; they rushed him out, and he too was in haste to leave, for YHWH had struck him. The expulsion from the sanctuary — the leper excluded from the holy space. Christ reversed this exile: he was himself cast outside the city (Heb 13:12: 'Jesus also suffered outside the gate'), sanctifying the outside — 'let us go to him outside the camp and bear the reproach he endured.'</p>",
    "21": "<p>Uzziah was a leper to the day of his death, living in a separate house, excluded from YHWH's house. His son Jotham was over the palace, governing the people. The king who sought unauthorized entry into the sacred space was permanently excluded from it. Christ secures permanent inclusion for those who were excluded: 'I am the living bread that came down from heaven' (John 6:51); 'in my Father's house are many rooms' (John 14:2) — exclusion reversed into permanent welcome.</p>",
    "22": "<p>Isaiah the prophet wrote the acts of Uzziah, from first to last. The same Isaiah who saw the vision of the seraphim and the divine throne in the year of Uzziah's death (Isa 6:1) and who wrote the servant songs (Isa 52-53). The Chronicler's note connects the king's reign to the prophetic record that will be fulfilled in Christ — Isaiah's literary legacy is the most explicitly messianic of all the prophetic books.</p>",
    "23": "<p>Uzziah slept with his fathers; they buried him near his fathers in the burial field belonging to the kings, for they said, 'He is a leper.' Even in death he was not given full royal burial honors — his leprosy followed him to the tomb. Christ was buried in a borrowed tomb (Matt 27:60) and then departed it — 'he is not here, for he has risen' (Matt 28:6). The tomb is not the end of his story as it was for Uzziah; the resurrection inaugurates the eternal royal honor his earthly story could not end with.</p>"
  },
  "27": {
    "1": "<p>Jotham was 25 and reigned 16 years in Jerusalem. His mother was Jerushah daughter of Zadok — a priestly family name, significant in a chapter about a king who respects priestly prerogatives. The priest-family mother of the faithful son is the Chronicler's genealogical commentary. Christ is born of priestly and royal lineage combined: Mary of the tribe of Levi (Elizabeth her relative was of Aaron, Luke 1:36), and the Davidic legal line through Joseph.</p>",
    "2": "<p>Jotham did what was right in the eyes of YHWH according to all his father Uzziah had done — but unlike him he did not enter the temple of YHWH. Jotham's positive characteristic is a restraint: he did not repeat his father's sin. The negative clause ('did not enter the temple') becomes the positive statement of his reign. Christ's faithfulness is also characterized in part by what he refused: he 'was in every respect tempted as we are, yet without sin' (Heb 4:15). The <em>without</em> is constitutive of the qualification for the priesthood he holds.</p>",
    "3": "<p>Jotham built the upper gate of the house of YHWH; he built extensively on the wall of Ophel; he built cities in the Judean hills and forts and towers in the wooded areas. The building program of the faithful king — investing in infrastructure without grasping priestly prerogatives. 'Unless the LORD builds the house, those who build it labor in vain' (Ps 127:1); Christ is the master builder whose building program is the church he raises (Matt 16:18).</p>",
    "4": "<p>Jotham built cities in the hill country of Judah and forts and towers in the wooded hills. The expansion of secure settlement into previously undeveloped territory. Christ's mission also reaches into previously unoccupied spiritual territory: 'I have been ambitious to preach the gospel, not where Christ has already been named, lest I build on someone else's foundation' (Rom 15:20) — the mission as frontier-settlement.</p>",
    "5": "<p>Jotham fought the king of the Ammonites and prevailed; the Ammonites gave him 100 talents of silver and 10,000 kors of wheat and barley for three years. The tribute-payment from Ammon acknowledges Jotham's covenantal authority in the region. Christ does not receive tribute in material goods but receives the tribute of worship: 'the nations will walk by its light, and the kings of the earth will bring their glory into it' (Rev 21:24) — the eschatological tribute that all earthly tribute types.</p>",
    "6": "<p>'Jotham became mighty because he ordered his ways before YHWH his God.' The causal chain: ordered covenant life → divine strengthening. Christ's own life demonstrates this principle from the inside: 'I do as the Father has commanded me' (John 14:31); 'he learned obedience through what he suffered, and being made perfect, he became the source of eternal salvation to all who obey him' (Heb 5:8-9). The ordered-ways-then-strength pattern is fulfilled perfectly in the incarnate Son.</p>",
    "7": "<p>The rest of the acts of Jotham, all his wars and his ways, are written in the Book of the Kings of Israel and Judah. The historical record as pointing beyond itself. All the acts of the kings are written; but of Christ's acts: 'the world itself could not contain the books that would be written' (John 21:25). The historical record of the kings is finite; the record of the King of kings exceeds all recording.</p>",
    "8": "<p>He was 25 years old when he began to reign and he reigned 16 years in Jerusalem. The reign duration — the same introductory data as v. 1, a closing formula for the reign. Christ's 'reign duration' is not bounded: 'of his kingdom there will be no end' (Luke 1:33). The formulaic close that ends every king's account has no place in the account of the eternal King.</p>",
    "9": "<p>Jotham slept with his fathers and they buried him in the city of David; and Ahaz his son reigned in his place. The transition from the faithful son to the unfaithful son — the most dramatic reversal between adjacent reigns in Chronicles. Christ's kingdom does not pass to an unworthy successor; 'he holds his priesthood permanently, because he continues forever' (Heb 7:24). The succession problem that plagues the Davidic line is resolved in the permanent priest-king who never dies into his successor.</p>"
  },
  "28": {
    "1": "<p>Ahaz was 20 and reigned 16 years in Jerusalem. He did not do right in YHWH's eyes, 'as his father David had done.' The Davidic standard is explicitly cited — and explicitly violated. Ahaz represents the anti-David: each of David's defining characteristics (seeking God, covenant loyalty, building toward the temple) is negated by Ahaz's reign. Christ is the fulfillment of the Davidic ideal: 'the son of David' (Matt 1:1) who recapitulates all that David sought and actualizes it.</p>",
    "2": "<p>Ahaz walked in the ways of the kings of Israel; he also made metal images for the Baals. The Baal-apostasy in the southern kingdom — adopting the sins of the north that led to its fall. Christ is the antithesis of the idol-walker: 'No one knows the Father except the Son' (Matt 11:27); the one who reveals the true character of God is the alternative to every Baal — every power misnamed as divine.</p>",
    "3": "<p>He burned incense in the Valley of the Son of Hinnom (<em>gêʾ-hinnōm</em>) and burned his children in the fire, following the detestable practices of the nations. The Valley of Hinnom — Gehenna — the historical site of child-sacrifice, which becomes the NT term for the place of eschatological judgment. Christ speaks of Gehenna as the place to be feared (Matt 10:28: 'fear him who can destroy both soul and body in hell'). He came 'to destroy the works of the devil' (1 John 3:8), including the demonic child-sacrifice system Ahaz practiced.</p>",
    "4": "<p>He sacrificed and burned incense on the high places, on the hills, and under every green tree. The multiplication of unauthorized worship sites — the decentralized idolatry that the Deuteronomic reform program aimed to eliminate. Christ calls worshippers away from all localized idolatry: 'the true worshippers will worship the Father in spirit and truth' (John 4:23) — not tied to any hill or tree but to the one who is himself the way to the Father.</p>",
    "5": "<p>YHWH gave Ahaz into the hand of the king of Aram, who struck him and took captive a great number. Also into the hand of the king of Israel, who struck him with a great blow. The double defeat by Aram and Israel — the covenant curse of being given into the hand of enemies (Deut 28:25). Christ bore this 'given into the hand' formula on behalf of his people: 'the Son of Man is about to be delivered into the hands of men' (Matt 17:22) — the representative king experiencing the covenant curse so the people need not.</p>",
    "6": "<p>Pekah son of Remaliah killed 120,000 valiant men in Judah in one day, because they had forsaken YHWH. The scale of covenant-judgment catastrophe. The Chronicler assigns causation explicitly: apostasy → abandonment by YHWH → military slaughter. Christ absorbs the ultimate apostasy-penalty: 'My God, my God, why have you forsaken me?' (Matt 27:46) — the cry of divine abandonment that the covenant curses of Deut 28 threatened, experienced by the one who had not forsaken God.</p>",
    "7": "<p>Zichri, a mighty man of Ephraim, killed the king's son Maaseiah, Azrikam the commander of the palace, and Elkanah the second in command to the king. The royal family and command structure decimated. In Christ's death the disciples who constituted his inner circle were scattered (Mark 14:50); but his resurrection reestablishes and commissions them (John 20:21-22).</p>",
    "8": "<p>The men of Israel took captive 200,000 of their brothers' wives, sons, and daughters, and also took much plunder. The massive captive-taking — brothers enslaving brothers in the covenant family. Christ comes to proclaim 'liberty to captives and recovering of sight to the blind, to set at liberty those who are oppressed' (Luke 4:18) — the Isaiah 61 mission that reverses the captive-taking pattern of Ahaz's day.</p>",
    "9": "<p>Oded the prophet of YHWH met the army of Samaria and said: 'The LORD, the God of your fathers, was angry with Judah, so he gave them into your hand; but you have killed them in a rage that has reached up to heaven.' The northern prophet intercedes across the political divide. Christ is the ultimate cross-boundary intercessor: 'Father, forgive them, for they know not what they do' (Luke 23:34) — intercession at the moment of the greatest injustice.</p>",
    "10": "<p>The captors propose to hold the Judahites as male and female slaves. Oded counters: 'are there not sins of your own against the LORD your God?' The tu quoque of the prophet — the captors are themselves guilty. Paul makes the same move in Rom 2:1: 'Therefore you have no excuse, O man, every one of you who judges. For in passing judgment on another you condemn yourself.' Christ alone has no sins of his own against the Father and so stands as the sole qualified judge (John 8:46: 'which one of you convicts me of sin?').</p>",
    "11": "<p>'Now hear me, and send back the captives whom you have taken from your brothers, for the fierce wrath of the LORD is upon you.' The prophetic call to release — the Jubilee logic applied across political lines. Christ's mission is the ultimate release: 'if the Son sets you free, you will be free indeed' (John 8:36). The captive-releasing mandate of the OT prophets finds its fulfillment in the one who was himself taken captive (arrested) to secure the permanent release of others.</p>",
    "12": "<p>Certain chiefs of Ephraim stood up against those returning from battle: Azariah son of Johanan, Berechiah son of Meshillemoth, Jehizkiah son of Shallum, and Amasa son of Hadlai. Named individuals who take a stand against injustice from within the northern tribe. Ordinary people of faith who act against the grain of their political moment — a recurring pattern in the biblical narrative; Christ's own family of disciples is similarly constituted from unlikely individuals who respond to the Spirit's prompting.</p>",
    "13": "<p>'You shall not bring the captives in here, for you propose to bring upon us guilt against the LORD in addition to our present sins and guilt. For our guilt is already great, and there is fierce anger against Israel.' The covenant-awareness of accumulated guilt — the leaders of Ephraim understand that adding to sin compounds judgment. Christ comes to deal with accumulated guilt: 'the Lamb of God, who takes away the sin of the world' (John 1:29) — not adding to guilt but removing it in a single comprehensive act.</p>",
    "14": "<p>The armed men left the captives and the plunder before the princes and all the assembly. The response to the prophetic and community moral pressure — the armed men stand down. The coercive power yields to the word. Christ's word also disarms: when he said 'I am he,' they drew back and fell to the ground (John 18:6) — the power of his self-disclosure exceeds any military capability.</p>",
    "15": "<p>The named men rose and took the captives, and from the plunder they clothed those who were naked, gave them sandals, fed them, gave them drink, anointed them with oil, carried those who were faint on donkeys, and brought them to Jericho. The seven-act compassion chain toward enemy captives is the OT's closest narrative parallel to the Good Samaritan (Luke 10:33-35): clothing, sandals, food, drink, anointing, transport — the same acts, the same endpoint (Jericho), the same unexpected agents of compassion. Christ embodies this compassion absolutely: 'I was naked and you clothed me... I was sick and you visited me, I was in prison and you came to me' (Matt 25:35-36).</p>",
    "16": "<p>At that time King Ahaz sent to the king of Assyria for help. The appeal to empire for security against coalition threat — the Ahaz solution. Isaiah specifically condemns this appeal and offers the Immanuel sign instead (Isa 7:9-14). Christ is the Immanuel that Ahaz refused: 'God with us' (Matt 1:23) is the divine help that does not require Assyrian alliance.</p>",
    "17": "<p>The Edomites had come again and struck Judah and carried away captives. Multiple simultaneous threats pressing on Judah. Christ's people also face multi-front pressure: 'in this world you will have tribulation' (John 16:33). But the promise continues: 'I have overcome the world' — the comprehensive victory that addresses simultaneous threats from every direction.</p>",
    "18": "<p>The Philistines had raided the cities in the Shephelah and the Negeb of Judah, and had taken Beth-shemesh, Aijalon, Gederoth, Soco with its villages, Timnah with its villages, and Gimzo with its villages. The piecemeal loss of lowland territories — Judah's geographic shrinkage under Ahaz. Under Christ, the kingdom expands rather than shrinks: 'the kingdom of heaven is like a grain of mustard seed that a man took and sowed in his field. It is the smallest of all seeds, but when it has grown it is larger than all the garden plants' (Matt 13:31-32). The representative king's faithfulness expands; the representative king's unfaithfulness contracts.</p>",
    "19": "<p>YHWH humbled Judah because of Ahaz king of Israel, for he had made Judah act sinfully and had been very unfaithful to the LORD. The representative king principle — the whole nation is humbled because of one king's apostasy. Christ is the positive counterpart: his obedience and righteousness are credited to the whole people — 'for as by the one man's disobedience the many were made sinners, so by the one man's obedience the many will be made righteous' (Rom 5:19).</p>",
    "20": "<p>Tiglath-pileser king of Assyria came to him but afflicted him instead of strengthening him. The purchased alliance fails — the imperial power takes tribute but does not deliver on the implicit promise of protection. Christ delivers on every promise: 'I will never leave you nor forsake you' (Heb 13:5, citing Deut 31:6). The empire that takes and does not give is the anti-type of the king who gives and does not take.</p>",
    "21": "<p>Ahaz took from the house of YHWH, the house of the king, and the princes, and gave tribute to the king of Assyria; but it did not help him. The stripping of the temple to pay Assyria — using what was devoted to YHWH to secure pagan political alliance. Christ is stripped at the cross (his garments divided: Mark 15:24), but his stripping is not the depletion of holy resources for political survival — it is the willing outpouring of self for the salvation of others.</p>",
    "22": "<p>In the time of his distress, King Ahaz became yet more faithless to YHWH — this was that King Ahaz. The epitaphic formula: distress → more faithlessness. The opposite of the covenant pattern (distress → cry → repentance → restoration). Manasseh will reverse this pattern in ch 33 (distress → humility → restoration). Christ under distress is the ultimate alternative: 'who for the joy set before him endured the cross, despising the shame' (Heb 12:2) — suffering transformed into perseverance, not into faithlessness.</p>",
    "23": "<p>Ahaz sacrificed to the gods of Damascus, which had defeated him, saying 'Because the gods of the kings of Aram helped them, I will sacrifice to them that they may help me.' The logic of military outcome determining religious allegiance — the gods of the winners must be powerful. Christ exposes the bankruptcy of this logic: 'all authority in heaven and on earth has been given to me' (Matt 28:18) after a death that looked like defeat. The resurrection overturns the outcome-as-divine-verdict equation.</p>",
    "24": "<p>Ahaz gathered together the vessels of the house of God and cut them in pieces; he also shut the doors of the house of YHWH and made himself altars at every corner in Jerusalem. The double act: destroying the temple vessels and shutting the temple — the most comprehensive assault on covenant worship in the southern kingdom's history. Christ does the opposite: 'something greater than the temple is here' (Matt 12:6), and 'we have confidence to enter the holy places by the blood of Jesus, by the new and living way that he opened for us' (Heb 10:19-20). What Ahaz shut, Christ opens permanently.</p>",
    "25": "<p>In every city of Judah Ahaz made high places to burn incense to other gods, provoking YHWH the God of his fathers to anger. The multiplied altars replacing the one temple — the decentralization of false worship at the moment when the legitimate worship was shut. Christ calls back from scattered idolatry to himself: 'I am the way, and the truth, and the life. No one comes to the Father except through me' (John 14:6) — the singular path that replaces the many altars on every corner.</p>",
    "26": "<p>The rest of his acts and all his ways, from first to last, are written in the Book of the Kings of Judah and Israel. The historical record of Ahaz's reign. The Chronicler gives him no positive final notation — the acts written are the acts of an apostate. Christ's acts are written for a different purpose: 'these are written so that you may believe that Jesus is the Christ, the Son of God, and that by believing you may have life in his name' (John 20:31). The record written for judgment becomes, in the NT, the record written for faith and life.</p>",
    "27": "<p>Ahaz slept with his fathers and they buried him in the city of Jerusalem — not in the tombs of the kings of Israel. The final exclusion: denied burial in the royal tombs. The worst king of the southern kingdom is excluded from his own heritage at death. Christ was buried in another's tomb (Matt 27:60), excluded from any earthly claim to burial property — 'foxes have holes, and birds of the air have nests, but the Son of Man has nowhere to lay his head' (Matt 8:20) — yet his resurrection transforms the borrowed tomb into the site of the greatest victory in human history.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '2chronicles')
    merge_comm(c, DATA)
    save_comm('mkt-christ', '2chronicles', c)
    count = sum(len(v) for v in DATA.values())
    print(f'2chronicles mkt-christ: wrote {count} verses across ch 25-28')

if __name__ == '__main__':
    main()
